// RabbitMQ Management HTTP API MCP server — generated by mcpify. Do not hand-edit.
//
// Populates a store db's semantic_endpoints vec0 table with real
// embedding vectors. mcpify's Rust generator only creates this table's
// schema (see the plan's embeddings decision) — this binary is the single
// place vectors get computed, reusing the exact same embedding function the
// `search` tool calls at runtime (`services::embedding_service::embed`), so
// indexing-time and live-query embeddings are guaranteed to share the same
// model and vector space. Vectors are bound as a raw little-endian `f32`
// blob (sqlite-vec's native `FLOAT[N]` wire format) rather than a JSON
// array string — `services::embedding_service`'s `search`-side query code
// (Story R6) must encode/decode with this exact same byte layout.

use std::path::{Path, PathBuf};

use rabbitmq_mcp::data::store::{VERSION_STORE_FILES, open_store_read_write};
use rabbitmq_mcp::services::embedding_service::embed;

struct EndpointRow {
    operation_id: String,
    path: String,
    method: String,
    summary: Option<String>,
    description: Option<String>,
}

fn vector_to_le_bytes(vector: &[f32]) -> Vec<u8> {
    vector
        .iter()
        .flat_map(|value| value.to_le_bytes())
        .collect()
}

/// Populates one store file's `semantic_endpoints` table in place,
/// returning how many operations were (re)indexed.
fn populate_one(path: &Path) -> anyhow::Result<usize> {
    let conn = open_store_read_write(path)?;

    let mut select =
        conn.prepare("SELECT operation_id, path, method, summary, description FROM endpoints")?;
    let rows: Vec<EndpointRow> = select
        .query_map([], |row| {
            Ok(EndpointRow {
                operation_id: row.get(0)?,
                path: row.get(1)?,
                method: row.get(2)?,
                summary: row.get(3)?,
                description: row.get(4)?,
            })
        })?
        .collect::<Result<_, _>>()?;

    // sqlite-vec's vec0 virtual tables don't implement conflict resolution
    // (no ON CONFLICT / INSERT OR REPLACE support — a duplicate primary key
    // always raises a UNIQUE constraint error, regardless of the conflict
    // clause used), so re-running this script against a db that already has
    // rows requires an explicit delete before each insert to stay idempotent.
    let mut delete = conn.prepare("DELETE FROM semantic_endpoints WHERE operation_id = ?1")?;
    let mut insert =
        conn.prepare("INSERT INTO semantic_endpoints (operation_id, embedding) VALUES (?1, ?2)")?;

    // Sequential, not parallelized: keeps peak memory bounded regardless of
    // how many operations a spec declares, at the cost of total wall time —
    // an acceptable trade for a one-time setup script.
    let count = rows.len();
    for row in rows {
        let text = [
            Some(row.method),
            Some(row.path),
            row.summary,
            row.description,
        ]
        .into_iter()
        .flatten()
        .collect::<Vec<_>>()
        .join(" ");
        let vector = embed(&text)?;
        delete.execute(rusqlite::params![row.operation_id])?;
        insert.execute(rusqlite::params![
            row.operation_id,
            vector_to_le_bytes(&vector)
        ])?;
    }

    Ok(count)
}

/// Which store file(s) to populate: bare invocation now targets *every*
/// version this project's ledger knows about (`VERSION_STORE_FILES`),
/// matching what the generated `Dockerfile` already does explicitly via
/// `--all` — a bare invocation used to silently populate only
/// `mcp_store.db`, leaving every other version's store at 0 embedded rows
/// unless `--all` was remembered. `--all` is kept as an accepted (now
/// redundant) explicit flag for scripts that already pass it; an explicit
/// path still targets exactly that one file for a targeted re-run.
fn targets() -> Vec<PathBuf> {
    let mut args = std::env::args().skip(1);
    match args.next().as_deref() {
        Some("--all") | None => VERSION_STORE_FILES
            .iter()
            .map(|(_, file)| PathBuf::from(file))
            .collect(),
        Some(path) => vec![PathBuf::from(path)],
    }
}

/// Fails loudly (non-zero exit) instead of allowing a store to be reported
/// "populated" when `semantic_endpoints` ends up with fewer rows than
/// `endpoints` — which would otherwise mean some operations are silently
/// unsearchable. Lists the specific missing operation IDs so the failure is
/// actionable.
fn verify_complete(conn: &rusqlite::Connection, path: &Path) -> anyhow::Result<()> {
    let endpoints_count: i64 = conn.query_row("SELECT COUNT(*) FROM endpoints", [], |row| row.get(0))?;
    let semantic_count: i64 =
        conn.query_row("SELECT COUNT(*) FROM semantic_endpoints", [], |row| row.get(0))?;

    if semantic_count == endpoints_count {
        return Ok(());
    }

    let mut missing_stmt = conn.prepare(
        "SELECT operation_id FROM endpoints \
         WHERE operation_id NOT IN (SELECT operation_id FROM semantic_endpoints)",
    )?;
    let missing: Vec<String> = missing_stmt
        .query_map([], |row| row.get(0))?
        .collect::<Result<_, _>>()?;

    anyhow::bail!(
        "'{}': semantic_endpoints has {semantic_count} row(s) but endpoints has \
         {endpoints_count} — missing embeddings for operation_id(s): {}",
        path.display(),
        missing.join(", ")
    );
}

fn main() -> anyhow::Result<()> {
    for path in targets() {
        let count = populate_one(&path)?;
        let conn = open_store_read_write(&path)?;
        verify_complete(&conn, &path)?;
        println!(
            "populated embeddings for {count} operation(s) in '{}'",
            path.display()
        );
    }
    Ok(())
}
